private:
    using PointIterator = std::vector<std::pair<uint32_t, Vec3>>::iterator;

    std::unique_ptr<KDNode> buildKDTree(PointIterator start, PointIterator end, int depth) {
        if (start == end) {
            return nullptr;
        }

        int axis = depth % 3;
        PointIterator mid;

        if (axis == 0) {
            mid = start + (end - start) / 2;
            std::nth_element(start, mid, end, compareX);
        } else if (axis == 1) {
            mid = start + (end - start) / 2;
            std::nth_element(start, mid, end, compareY);
        } else {
            mid = start + (end - start) / 2;
            std::nth_element(start, mid, end, compareZ);
