        std::unique_ptr<KDNode> node = std::make_unique<KDNode>();
        node->entityId = mid->first;
        node->point = mid->second;
        node->left = buildKDTree(start, mid, depth + 1);
        node->right = buildKDTree(mid + 1, end, depth + 1);

        return node;
